+            }
+            if (where.right) |right| {
+                return evaluateCorrelatedWhere(table, right, row_idx, outer_table, outer_row, outer_alias, ctx);
+            }
+            return true;
+        },
+        .or_op => {
+            var result = false;
+            if (where.left) |left| {
+                result = evaluateCorrelatedWhere(table, left, row_idx, outer_table, outer_row, outer_alias, ctx);
